import React from 'react';
import BookingForm from '../components/BookingForm';

const Booking = () => {
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col pt-20">
      {/* Header Area */}
      <div className="bg-green-900 py-16 relative overflow-hidden">
        <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSI0MCIgaGVpZ2h0PSI0MCI+PGNpcmNsZSBjeD0iMjAiIGN5PSIyMCIgcj0iMSIgZmlsbD0icmdiYSgyNTUsMjU1LDI1NSwwLjA1KSIvPjwvc3ZnPg==')] opacity-20"></div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500 rounded-full mix-blend-multiply filter blur-3xl opacity-30"></div>

        <div className="relative max-w-3xl mx-auto px-4 text-center z-10">
          <h1 className="text-4xl md:text-5xl font-extrabold text-white tracking-tight mb-4">Reserve Your Adventure</h1>
          <p className="text-lg text-green-100 font-light">Secure your spot for the ultimate wildlife experience in Ranthambhore National Park.</p>
        </div>
      </div>

      {/* Form Container Area */}
      <div className="flex-grow flex items-start justify-center px-4 -mt-8 pb-24 relative z-20">
        <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-gray-100 p-6 md:p-10">
          <div className="mb-8 border-b border-gray-100 pb-6">
            <h2 className="text-2xl font-bold text-gray-900">Booking Details</h2>
            <p className="text-sm text-gray-500 mt-1">Please fill in the information below to request a safari slot.</p>
          </div>
          <BookingForm />
        </div>
      </div>
    </div>
  );
};

export default Booking;
